/// MolmoAct2 VLM pipeline: ViT + adapter + Qwen3-style LM.
///
/// Supports two high-level operations:
///
///   encode_image(pixels) → image_features [n_query, text_hidden]
///     Runs the ViT + adapter; returns visual token embeddings ready to be
///     prepended (or interleaved) with text token embeddings before forwarding
///     through the LM backbone.
///
///   generate_with_image(pixels, prompt_tokens, max_new_tokens) → Vec<u32>
///     Full VLM generation: encodes the image, builds an embed sequence
///     [<image features> | <text token embeds>], runs the LM, and samples
///     autoregressively until EOS or the token limit.
///
/// The LM backbone is the existing NativeLlamaPipeline instantiated with
/// arch = "qwen3" (since the text config is Qwen3-style with QK-norm). It
/// is held behind a Box so the caller owns one pipeline object for everything.
///
/// .knot layout expected by the Python encoder:
///   config.arch              = "molmoact2"
///   config.molmo_text        = { ... MolmoAct2TextConfig ... }
///   config.molmo_vit         = { ... MolmoAct2VitConfig ... }
///   config.molmo_adapter     = { ... MolmoAct2AdapterConfig ... }
///   tensors:
///     All LM tensors under standard knot names (blk_*_*, token_embd_weight…)
///     All ViT tensors under vit_* names
///     All adapter tensors under adapter_* names
use std::sync::Arc;

use crate::cat_map_route::CertifiedCatRoute;
use crate::loader::{KnotWeights, WeightBackend};
use crate::model::NativeLlamaPipeline;
use crate::model_molmoact2_action_expert::{ActionWithCatMapFastPath, MolmoAct2ActionExpert};
use crate::model_molmoact2_adapter::MolmoAct2Adapter;
use crate::model_molmoact2_config::MolmoAct2Config;
use crate::model_molmoact2_vit::MolmoAct2ViT;

// MolmoAct2 special token IDs (from config.json). Depth reasoning is autoregressive
// over a 128-code book at 100 spatial positions (10x10); the action expert then
// flow-matches conditioned on the depth-aware KV cache.
const DEPTH_TOKEN_START_ID: u32 = 153985;
const NUM_DEPTH_TOKENS: usize = 128; // depth codebook size
const NUM_DEPTH_CODES: usize = 100; // spatial positions (10x10)

pub struct MolmoAct2ActionContext {
    pub kv: Vec<(Vec<f32>, Vec<f32>)>,
    pub total_seq: usize,
}

pub struct MolmoAct2Pipeline {
    pub vit: MolmoAct2ViT,
    pub adapter: MolmoAct2Adapter,
    pub lm: NativeLlamaPipeline,
    pub action_expert: MolmoAct2ActionExpert,
    pub config: MolmoAct2Config,
}

impl MolmoAct2Pipeline {
    /// Construct from a KnotWeights that contains all three sub-model weights.
    pub fn from_knot(knot: KnotWeights) -> Self {
        // Parse the MolmoAct2Config from the knot's JSON metadata field.
        let config = Self::parse_config(&knot);

        let backend: Arc<dyn WeightBackend> = knot.backend.clone();

        let vit = MolmoAct2ViT::new(config.vit_config.clone(), backend.clone());
        let adapter = MolmoAct2Adapter::new(config.adapter_config.clone(), backend.clone());
        let action_expert =
            MolmoAct2ActionExpert::new(config.action_expert_config.clone(), backend.clone());

        // The LM is a standard NativeLlamaPipeline — the knot's top-level
        // KnotConfig must have arch="qwen3" and the matching text backbone dims
        // so from_knot sets up QK-norm, GQA, etc. correctly.
        let lm = NativeLlamaPipeline::from_knot(knot, false, 0.0);

        Self {
            vit,
            adapter,
            lm,
            action_expert,
            config,
        }
    }

    /// Convenience: load from a local file path.
    #[cfg(not(target_arch = "wasm32"))]
    pub fn load(path: &str) -> Self {
        let knot = KnotWeights::load(path).expect("failed to load molmoact2 knot");
        Self::from_knot(knot)
    }

    /// Step 1 — encode an image into visual token embeddings.
    ///
    /// `pixels`: f32 slice, CHW layout [3, 378, 378], normalized by caller.
    ///
    /// Returns `[n_query_tokens, text_hidden_size]` float32 — ready to be
    /// placed in the residual stream before text token embeddings.
    pub fn encode_image(&mut self, pixels: &[f32]) -> Result<Vec<f32>, String> {
        let n_patches = self.config.vit_config.n_patches();
        let vit_out = self.vit.forward(pixels)?;
        let image_features = self.adapter.forward(&vit_out, n_patches)?;
        Ok(image_features)
    }

    /// Step 2 — generate text conditioned on an image + prompt tokens.
    ///
    /// `pixels`: CHW float32 image (see encode_image).
    /// `prompt_tokens`: text token IDs (after the image tokens in the model's scheme).
    /// `max_new`: token budget for generation.
    /// `eos_token`: stop when this ID is sampled.
    ///
    /// Returns generated token IDs (not including the prompt or image tokens).
    pub fn generate_with_image(
        &mut self,
        pixels: &[f32],
        prompt_tokens: &[u32],
        max_new: usize,
        eos_token: u32,
    ) -> Result<Vec<u32>, String> {
        // Encode image → visual residual [n_vis, text_hidden]
        let image_feats = self.encode_image(pixels)?;
        let n_vis = self.config.adapter_config.num_query_tokens;
        let text_h = self.config.adapter_config.text_hidden_size;

        // Get text token embeddings from the LM [n_text, text_hidden].
        let text_embeds = self.lm.embed_chunk(prompt_tokens, 0)?;
        let n_text = prompt_tokens.len();

        // Concatenate [image | text] into a single residual.
        let seq_len = n_vis + n_text;
        let mut combined = vec![0.0f32; seq_len * text_h];
        combined[..n_vis * text_h].copy_from_slice(&image_feats);
        combined[n_vis * text_h..].copy_from_slice(&text_embeds);

        // Full LM forward over the combined prefill.
        let n_layers = self.config.text_config.num_hidden_layers;
        let mut hidden = self
            .lm
            .forward_range_chunk(&combined, 0, n_layers, 0, seq_len)?;

        // Sample the first new token.
        let mut generated = Vec::with_capacity(max_new);
        let logits = self.lm.lm_head_only(&hidden[(seq_len - 1) * text_h..], 1)?;
        let next_tok = argmax(&logits);
        if next_tok == eos_token {
            return Ok(generated);
        }
        generated.push(next_tok);

        // Autoregressive decode.
        for step in 1..max_new {
            let pos = seq_len + step - 1;
            let tok_embed = self.lm.embed_chunk(&[generated[step - 1]], pos)?;
            hidden = self
                .lm
                .forward_range_chunk(&tok_embed, 0, n_layers, pos, 1)?;
            let logits = self.lm.lm_head_only(&hidden, 1)?;
            let tok = argmax(&logits);
            if tok == eos_token {
                break;
            }
            generated.push(tok);
        }

        Ok(generated)
    }

    /// Vision-language-ACTION: image + instruction → robot action chunk.
    ///
    /// Pipeline (matches HF MolmoAct2 continuous-action inference):
    ///   1. ViT + adapter encode the image into visual tokens.
    ///   2. Prefill the LM over [image | instruction], populating the KV cache.
    ///   3. Autoregressively emit NUM_DEPTH_CODES depth tokens (greedy argmax over
    ///      the 128-code depth book, reusing the LM head) so the KV cache becomes
    ///      depth-aware.
    ///   4. Extract per-layer K/V and run the action expert's flow-matching loop.
    ///
    /// Returns the model-space action chunk `[horizon * max_action_dim]`. The
    /// caller q01_q99-unnormalizes per robot tag to get physical actions.
    pub fn generate_action(
        &mut self,
        pixels: &[f32],
        prompt_tokens: &[u32],
        horizon: usize,
        seed: u64,
    ) -> Result<Vec<f32>, String> {
        let context = self.prepare_action_context(pixels, prompt_tokens)?;
        self.action_expert
            .generate(&context.kv, context.total_seq, horizon, seed)
    }

    pub fn generate_action_with_cat_map_fast_path(
        &mut self,
        pixels: &[f32],
        prompt_tokens: &[u32],
        horizon: usize,
        seed: u64,
        route: CertifiedCatRoute,
        convergence_epsilon: f32,
    ) -> Result<ActionWithCatMapFastPath, String> {
        let context = self.prepare_action_context(pixels, prompt_tokens)?;
        self.action_expert.generate_with_cat_map_fast_path(
            &context.kv,
            context.total_seq,
            horizon,
            seed,
            route,
            convergence_epsilon,
        )
    }

    /// Build the depth-aware per-layer K/V cache used by the action expert.
    /// Benchmark callers can prepare this once, then compare action-flow
    /// variants without charging image encoding or LM depth reasoning each run.
    pub fn prepare_action_context(
        &mut self,
        pixels: &[f32],
        prompt_tokens: &[u32],
    ) -> Result<MolmoAct2ActionContext, String> {
        let n_layers = self.config.text_config.num_hidden_layers;
        let text_h = self.config.adapter_config.text_hidden_size;
        let vocab = self.config.text_config.vocab_size;

        // 1-2. Encode image + prefill [image | text].
        let image_feats = self.encode_image(pixels)?;
        let n_vis = self.config.adapter_config.num_query_tokens;
        let text_embeds = self
            .lm
            .embed_chunk(prompt_tokens, 0)
            .map_err(|e| e.to_string())?;
        let n_text = prompt_tokens.len();
        let prefill_len = n_vis + n_text;
        let mut combined = vec![0.0f32; prefill_len * text_h];
        combined[..n_vis * text_h].copy_from_slice(&image_feats);
        combined[n_vis * text_h..].copy_from_slice(&text_embeds);
        // forward_range_chunk caps at BATCH_CAPACITY (8) tokens/call — chunk the
        // [image | text] prefill into <=8-token pieces (KV lands in the cache).
        const PREFILL_CHUNK: usize = 8;
        let mut last_hidden: Vec<f32> = Vec::new();
        let mut cpos = 0usize;
        while cpos < prefill_len {
            let take = PREFILL_CHUNK.min(prefill_len - cpos);
            let chunk = &combined[cpos * text_h..(cpos + take) * text_h];
            let h = self
                .lm
                .forward_range_chunk(chunk, 0, n_layers, cpos, take)
                .map_err(|e| e.to_string())?;
            if cpos + take == prefill_len {
                last_hidden = h[(take - 1) * text_h..take * text_h].to_vec();
            }
            cpos += take;
        }

        // 3. Depth reasoning: greedy AR over the 128-code depth book (100 positions).
        // Project ONLY the 128 depth-code rows of the LM head, not the full vocab.
        let mut pos = prefill_len;
        let lo = DEPTH_TOKEN_START_ID as usize;
        let hi = (lo + NUM_DEPTH_TOKENS).min(vocab);
        for _ in 0..NUM_DEPTH_CODES {
            let logits = self
                .lm
                .lm_head_range(&last_hidden, 1, lo, hi)
                .map_err(|e| e.to_string())?;
            let mut best = 0usize;
            let mut best_v = f32::NEG_INFINITY;
            for (j, &val) in logits.iter().enumerate() {
                if val > best_v {
                    best_v = val;
                    best = j;
                }
            }
            let tok = (lo + best) as u32;
            let emb = self
                .lm
                .embed_chunk(&[tok], pos)
                .map_err(|e| e.to_string())?;
            let h = self
                .lm
                .forward_range_chunk(&emb, 0, n_layers, pos, 1)
                .map_err(|e| e.to_string())?;
            last_hidden = h[..text_h].to_vec();
            pos += 1;
        }

        // 4. Extract the depth-aware per-layer KV for the flow-matching expert.
        let total_seq = pos;
        let kv = self.lm.extract_layer_kv(total_seq);
        Ok(MolmoAct2ActionContext { kv, total_seq })
    }

    fn parse_config(_knot: &KnotWeights) -> MolmoAct2Config {
        // The Python encoder stores the sub-configs in the knot metadata as JSON
        // under the key "molmo_config". Fall back to defaults if absent.
        MolmoAct2Config::default()
    }
}

fn argmax(v: &[f32]) -> u32 {
    v.iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
        .map(|(i, _)| i as u32)
        .unwrap_or(0)
}
